async function check() {
  const r = await fetch('https://chore-js-vanilla-rewrite-pha.begbie-hugo.pages.dev/');
  const html = await r.text();
  return html.includes('link href=/scss/style.min.css') || html.includes('href="/scss/style.min.css"');
}

const deadline = Date.now() + 5 * 60 * 1000; // 5 minutes
let ready = false;
while (Date.now() < deadline) {
  try {
    ready = await check();
  } catch (e) {
    ready = false;
  }
  if (ready) break;
  await new Promise(res => setTimeout(res, 15000));
}
